// worker1.js - Public-facing worker
export default {
  async fetch(request, env) {
    try {
      const url = new URL(request.url);
      
      // Validate request
      if (!url.pathname.startsWith('/api/')) {
        return new Response('Invalid endpoint', { status: 404 });
      }
      
      // Forward to internal worker via service binding
      const response = await env.INTERNAL_WORKER.fetch(request);
      
      return response;
    } catch (error) {
      return new Response('Internal error', { status: 500 });
    }
  }
};

// worker2.js - Internal processing worker
export default {
  async fetch(request, env) {
    try {
      const url = new URL(request.url);
      const method = request.method;
      
      // Validate and sanitize inputs
      if (method !== 'GET' && method !== 'POST') {
        return new Response('Method not allowed', { status: 405 });
      }
      
      // Process request
      let result = {};
      
      if (method === 'POST') {
        const body = await request.json();
        // Validate body
        if (!body || typeof body !== 'object') {
          return new Response('Invalid request body', { status: 400 });
        }
        
        // Process data
        result = { processed: true, data: body };
      } else {
        result = { message: 'Hello from internal worker' };
      }
      
      return new Response(JSON.stringify(result), {
        headers: { 'Content-Type': 'application/json' }
      });
    } catch (error) {
      return new Response('Processing error', { status: 500 });
    }
  }
};

